"""LLM adapters for AI-powered triage and response generation.

Supports multiple LLM providers with a unified interface.
"""

from __future__ import annotations

import abc
import json
import os
from typing import Any, Dict, List, Optional, Tuple

import yaml


class LLMProvider:
    """Enum of supported LLM providers."""

    OPENAI = "openai"
    ANTHROPIC = "anthropic"
    LOCAL = "local"
    MOCK = "mock"


class LLMConfig:
    """Configuration for an LLM provider."""

    def __init__(
        self,
        provider: str = LLMProvider.MOCK,
        model: str = "gpt-4o-mini",
        api_key: Optional[str] = None,
        base_url: Optional[str] = None,
        temperature: float = 0.0,
        max_tokens: int = 1024,
        timeout: int = 30,
        **kwargs: Any,
    ):
        self.provider = provider
        self.model = model
        self.api_key = api_key or os.environ.get(
            f"{provider.upper()}_API_KEY", "mock-key"
        )
        self.base_url = base_url
        self.temperature = temperature
        self.max_tokens = max_tokens
        self.timeout = timeout
        self.extra = kwargs

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> LLMConfig:
        """Create config from dictionary."""
        return cls(**data)

    @classmethod
    def from_yaml(cls, path: str) -> LLMConfig:
        """Create config from YAML file."""
        with open(path, "r") as f:
            data = yaml.safe_load(f)
        return cls.from_dict(data)


class LLMMessage:
    """Represents a chat message."""

    def __init__(self, role: str, content: str, name: Optional[str] = None):
        self.role = role  # "system", "user", "assistant"
        self.content = content
        self.name = name

    def to_dict(self) -> Dict[str, str]:
        d = {"role": self.role, "content": self.content}
        if self.name:
            d["name"] = self.name
        return d


class LLMResponse:
    """Represents an LLM response."""

    def __init__(
        self,
        content: str,
        model: str,
        usage: Optional[Dict[str, int]] = None,
        finish_reason: Optional[str] = None,
        metadata: Optional[Dict[str, Any]] = None,
    ):
        self.content = content
        self.model = model
        self.usage = usage or {}
        self.finish_reason = finish_reason
        self.metadata = metadata or {}

    @property
    def text(self) -> str:
        return self.content

    def to_dict(self) -> Dict[str, Any]:
        return {
            "content": self.content,
            "model": self.model,
            "usage": self.usage,
            "finish_reason": self.finish_reason,
            "metadata": self.metadata,
        }


class BaseLLMAdapter(abc.ABC):
    """Abstract base class for LLM adapters."""

    @abc.abstractmethod
    def chat(
        self,
        messages: List[LLMMessage],
        temperature: Optional[float] = None,
        max_tokens: Optional[int] = None,
        **kwargs: Any,
    ) -> LLMResponse:
        """Send a chat completion request."""
        ...

    @abc.abstractmethod
    def chat_stream(
        self,
        messages: List[LLMMessage],
        temperature: Optional[float] = None,
        max_tokens: Optional[int] = None,
        **kwargs: Any,
    ):
        """Send a streaming chat completion request. Yields chunks."""
        ...

    @abc.abstractmethod
    def classify(
        self,
        text: str,
        categories: List[str],
        **kwargs: Any,
    ) -> Tuple[str, float]:
        """Classify text into one of the given categories.

        Returns:
            Tuple of (predicted_category, confidence_score)
        """
        ...

    @abc.abstractmethod
    def extract_json(
        self,
        text: str,
        schema: Dict[str, Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """Extract structured data from text using LLM.

        Returns:
            Dictionary of extracted data.
        """
        ...

    def get_config(self) -> LLMConfig:
        """Return the adapter's configuration."""
        return self._config

    @property
    @abc.abstractmethod
    def model_name(self) -> str:
        """Return the model name."""
        ...


class MockLLMAdapter(BaseLLMAdapter):
    """Mock LLM adapter for testing and development."""

    def __init__(self, config: Optional[LLMConfig] = None):
        self._config = config or LLMConfig(provider=LLMProvider.MOCK)

    @property
    def model_name(self) -> str:
        return "mock-gpt-4o-mini"

    def chat(
